exercise.solution:
function getTicketPrice(age) {
  if (age < 5) {
    return "Free";
  } else if (age <= 12) {
    return "$8";
  } else if (age <= 64) {
    return "$15";
  } else {
    return "$10";
  }
}

console.log(getTicketPrice(3));   // Free
console.log(getTicketPrice(10));  // $8
console.log(getTicketPrice(30));  // $15
console.log(getTicketPrice(70));  // $10
